import type { AuthSessionData } from "../types/auth";

export const AUTH_SESSION_REFRESH_BUFFER_MS = 60_000;

export type LoginStartOptions = {
  identityProvider?: "Google";
  redirectTo?: string;
  screenHint?: "sign_up";
};

export interface LoginOptions {
  identityProvider?: "Google";
  screenHint?: "sign_up";
}

export function buildLoginStartPath(options: LoginStartOptions = {}) {
  const searchParams = new URLSearchParams();

  if (options.identityProvider) {
    searchParams.set("identity_provider", options.identityProvider);
  }

  if (options.redirectTo) {
    searchParams.set("redirect_to", options.redirectTo);
  }

  if (options.screenHint) {
    searchParams.set("screen_hint", options.screenHint);
  }

  const search = searchParams.toString();
  return search ? `/oauth/start?${search}` : "/oauth/start";
}

export function calculateExpiresAt(expiresInSeconds: number, now = Date.now()) {
  return now + expiresInSeconds * 1000;
}

export function hasActiveAuthSession(
  session: AuthSessionData,
  now = Date.now(),
) {
  return Boolean(
    session.accessToken && session.expiresAt && session.expiresAt > now,
  );
}

export function isAuthSessionWithinRefreshBuffer(
  session: AuthSessionData,
  now = Date.now(),
  refreshBufferMs = AUTH_SESSION_REFRESH_BUFFER_MS,
) {
  return Boolean(
    session.accessToken &&
      session.expiresAt &&
      session.expiresAt - now <= refreshBufferMs,
  );
}

export function normalizePostLoginRedirect(redirectTo?: string | null) {
  if (!redirectTo) {
    return undefined;
  }

  if (!redirectTo.startsWith("/") || redirectTo.startsWith("//")) {
    return undefined;
  }

  return redirectTo;
}
