import { env } from "@/env";
import { buildLoginStartPath, type LoginOptions } from "@/lib/auth";
import { useAuthTokenSession } from "@/server/session.server";
import { redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";

export const redirectIfAuthenticated = createServerFn().handler(async () => {
  const session = await useAuthTokenSession();
  const hasAuthToken = !!session.data.authToken;

  if (env.VITE_TEMP_BYPASS_AUTH) {
    return;
  }

  if (hasAuthToken) {
    throw redirect({
      to: "/",
    });
  }
});

export async function initiateLogin(options: LoginOptions = {}): Promise<void> {
  window.location.assign(
    buildLoginStartPath({
      identityProvider: options.identityProvider,
      screenHint: options.screenHint,
    }),
  );
}

export async function redirectToLogin(): Promise<void> {
  await initiateLogin();
}

export async function initiateSignup(
  options: LoginOptions = {},
): Promise<void> {
  await initiateLogin({ ...options, screenHint: "sign_up" });
}
