```1:140:/Users/duhl/git/ui/apps/org-next/src/server/org-api.server.ts
import { env } from "@/env";
import { RMP_MOCK_HEADER } from "@/mocks/rmp-constants";
import { useAuthTokenSession } from "@/server/session.server";
import { createServerOnlyFn } from "@tanstack/react-start";
import { getRequestHeaders } from "@tanstack/start-server-core";
import { OrgApiError } from "./error";
import { logServerErrorToRollbar } from "./rollbar-server.server";

function forwardRmpMockHeader(): Record<string, string> {
  if (!env.VITE_ENABLE_RMP) {
    return {};
  }
  try {
    const incoming = getRequestHeaders();
    const mock = incoming.get(RMP_MOCK_HEADER);
    if (mock) {
      return { [RMP_MOCK_HEADER]: mock };
    }
  } catch {
    // No TanStack request context (e.g. startup); real API only.
  }
  return {};
}

const MAX_BODY_LOG_LENGTH = 1000;

const truncateForLog = (value: string) =>
  value.length > MAX_BODY_LOG_LENGTH
    ? `${value.slice(0, MAX_BODY_LOG_LENGTH)}…`
    : value;

const shouldSkipRollbarForStatus = (status: number) => status === 401;

const requestOrgApiJson = createServerOnlyFn(
  async <T>(
    path: string,
    {
      body,
      method = "GET",
    }: {
      body?: unknown;
      method?: "GET" | "POST" | "PUT";
    } = {},
  ): Promise<T> => {
    const accessToken = await getOrgApiAccessToken();
    if (!accessToken) {
      throw new OrgApiError("Failed to resolve access token", 401);
    }
    const hasBody = body !== undefined;

    const apiHostname = env.API_HOSTNAME;
    const url = new URL(path, apiHostname);

    let response: Response;
    try {
      response = await fetch(url.toString(), {
        body: hasBody ? JSON.stringify(body) : undefined,
        headers: {
          Accept: "application/json",
          Authorization: `Bearer ${accessToken}`,
          ...(hasBody ? { "Content-Type": "application/json" } : {}),
          "X-APP": "anedot:3",
          "X-Api-Version": "1",
          "X-Requested-With": "XMLHttpRequest",
          ...forwardRmpMockHeader(),
        },
        method,
      });
    } catch (cause) {
      const err = cause instanceof Error ? cause : new Error(String(cause));
      logServerErrorToRollbar(err, {
        method,
        orgApiFetchFailed: true,
        path,
        url: url.toString(),
      });
      throw cause;
    }

    if (!response.ok) {
      const errorText = await response.text();
      const status = response.status;
      const message = errorText || `Request failed for ${path}`;
      const apiError = new OrgApiError(message, status);

      if (!shouldSkipRollbarForStatus(status)) {
        logServerErrorToRollbar(apiError, {
          method,
          orgApiErrorResponse: true,
          path,
          responseBody: truncateForLog(errorText || ""),
          status,
          url: url.toString(),
        });
      }

      throw apiError;
    }

    try {
      return (await response.json()) as T;
    } catch (cause) {
      const err = cause instanceof Error ? cause : new Error(String(cause));
      logServerErrorToRollbar(err, {
        method,
        orgApiJsonParseFailed: true,
        path,
        url: url.toString(),
      });
      throw cause;
    }
  },
);

export const getOrgApiJson = createServerOnlyFn(
  async <T>(path: string): Promise<T> => {
    return requestOrgApiJson(path);
  },
);

export const postOrgApiJson = createServerOnlyFn(
  async <T>(path: string, body: unknown): Promise<T> => {
    return requestOrgApiJson(path, { body, method: "POST" });
  },
);

export const putOrgApiJson = createServerOnlyFn(
  async <T>(path: string, body: unknown): Promise<T> => {
    return requestOrgApiJson(path, { body, method: "PUT" });
  },
);

const getOrgApiAccessToken = createServerOnlyFn(
  async (): Promise<string | null> => {
    const authTokenSession = await useAuthTokenSession();

    return env.MOCK_ACCESS_TOKEN ?? authTokenSession.data.authToken ?? null;
  },
);
```

### `src/server/app-bootstrap.ts` (bootstrap = “who am I” for authed routes)

```1:79:/Users/duhl/git/ui/apps/org-next/src/server/app-bootstrap.ts
import type { AppBootstrap, Tenant, User } from "@/types/bootstrap";
import { redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { OrgApiError } from "./error";
import { getOrgApiJson } from "./org-api.server";

const fetchCurrentUser = createServerFn({ method: "GET" }).handler(
  async (): Promise<User | null> => {
    try {
      return await getOrgApiJson<User>("/users/me");
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 404) {
        return null;
      }

      throw error;
    }
  },
);

const fetchTenants = createServerFn({ method: "GET" }).handler(
  async (): Promise<Tenant[]> => {
    try {
      return await getOrgApiJson<Tenant[]>("/tenants");
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw error;
      }

      return [];
    }
  },
);

async function fetchAppBootstrapData({
  tenantId,
}: {
  tenantId?: number;
} = {}): Promise<AppBootstrap | null> {
  const user = await fetchCurrentUser();
  if (user === null) {
    return null;
  }
  const tenants = await fetchTenants();

  const currentTenant = tenantId
    ? (tenants.find((tenant) => tenant.id === tenantId) ?? null)
    : null;

  return {
    currentTenant,
    currentUser: user,
    tenant: currentTenant,
    tenants,
    user,
    users: [user],
  };
}

export const getAppBootstrapData = createServerFn({ method: "GET" }).handler(
  async (): Promise<AppBootstrap> => {
    try {
      const appBootstrap = await fetchAppBootstrapData();

      if (!appBootstrap) {
        throw redirect({ to: "/login" });
      }

      return appBootstrap;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      throw error;
    }
  },
);
